def L_ops(a,b,c):
    return [[matrix(ZZ,[[a,_sage_const_0 ],[_sage_const_0 ,b]]),matrix(ZZ,[[_sage_const_0 ,_sage_const_0 ],[c,_sage_const_0 ]])],
            [matrix(ZZ,[[_sage_const_0 ,c],[_sage_const_0 ,_sage_const_0 ]]),matrix(ZZ,[[b,_sage_const_0 ],[_sage_const_0 ,a]])]]
def embed(op,i,L):
    I2=identity_matrix(ZZ,_sage_const_2 ); m=[op if k==i else I2 for k in range(L)]
    M=m[_sage_const_0 ]
    for k in range(_sage_const_1 ,L): M=M.tensor_product(m[k])
    return M
def transfer_matrix(L,a,b,c):
    dim=_sage_const_2 **L; Lo=L_ops(a,b,c)
    M=[[identity_matrix(ZZ,dim),zero_matrix(ZZ,dim)],[zero_matrix(ZZ,dim),identity_matrix(ZZ,dim)]]
    for i in range(L):
        Li=[[embed(Lo[r][s],i,L) for s in range(_sage_const_2 )] for r in range(_sage_const_2 )]
        M=[[M[_sage_const_0 ][_sage_const_0 ]*Li[_sage_const_0 ][_sage_const_0 ]+M[_sage_const_0 ][_sage_const_1 ]*Li[_sage_const_1 ][_sage_const_0 ], M[_sage_const_0 ][_sage_const_0 ]*Li[_sage_const_0 ][_sage_const_1 ]+M[_sage_const_0 ][_sage_const_1 ]*Li[_sage_const_1 ][_sage_const_1 ]],
           [M[_sage_const_1 ][_sage_const_0 ]*Li[_sage_const_0 ][_sage_const_0 ]+M[_sage_const_1 ][_sage_const_1 ]*Li[_sage_const_1 ][_sage_const_0 ], M[_sage_const_1 ][_sage_const_0 ]*Li[_sage_const_0 ][_sage_const_1 ]+M[_sage_const_1 ][_sage_const_1 ]*Li[_sage_const_1 ][_sage_const_1 ]]]
    return M[_sage_const_0 ][_sage_const_0 ]+M[_sage_const_1 ][_sage_const_1 ]

def matrix_power_period(T, m, maxN=_sage_const_2000 ):
    # T^N mod m の最終周期(と前周期)を Brent 的に検出
    R=Integers(m); Tm=T.change_ring(R)
    seen={}; P=Tm**_sage_const_1 ; N=_sage_const_1 
    seq=[]
    while N<=maxN:
        key=tuple(P.list())
        if key in seen:
            return seen[key], N-seen[key]   # (前周期開始, 周期)
        seen[key]=N; seq.append(P); P=P*Tm; N+=_sage_const_1 
    return None,None

def trunc_val(z,p,k):
    z=ZZ(z)
    if z==_sage_const_0 : return k
    return min(z.valuation(p), k)

